# pip install httpx
import httpx, os, json

# Read credentials from environment variables
OPENWEATHER_API_KEY = os.environ.get("OPENWEATHER_API_KEY", "")

def get_weather(city: str, country_code: str = "US") -> str:
    """
    Get current weather for a city using OpenWeatherMap API.
    country_code: ISO 3166 country code, e.g. 'US', 'GB', 'JP'.
    """
    if not OPENWEATHER_API_KEY:
        return "Error: OPENWEATHER_API_KEY environment variable not set."
    try:
        response = httpx.get(
            "https://api.openweathermap.org/data/2.5/weather",
            params={
                "q": f"{city},{country_code}",
                "appid": OPENWEATHER_API_KEY,
                "units": "metric",
            },
            timeout=10.0,  # always set a timeout
        )
        response.raise_for_status()
        data = response.json()
        temp = data["main"]["temp"]
        feels_like = data["main"]["feels_like"]
        description = data["weather"][0]["description"]
        humidity = data["main"]["humidity"]
        return (
            f"{city}: {description}, {temp:.1f}°C (feels like {feels_like:.1f}°C), "
            f"humidity {humidity}%"
        )
    except httpx.TimeoutException:
        return f"Error: weather API timed out for {city}."
    except httpx.HTTPStatusError as e:
        return f"Error: weather API returned {e.response.status_code} for {city}."
    except Exception as e:
        return f"Error: {e}"

def search_news(query: str, max_results: int = 3) -> str:
    """
    Search recent news articles. Returns titles and summaries.
    """
    NEWSAPI_KEY = os.environ.get("NEWSAPI_KEY", "")
    if not NEWSAPI_KEY:
        return "Error: NEWSAPI_KEY environment variable not set."
    try:
        response = httpx.get(
            "https://newsapi.org/v2/everything",
            params={
                "q": query,
                "sortBy": "publishedAt",
                "pageSize": max_results,
                "apiKey": NEWSAPI_KEY,
            },
            timeout=10.0,
        )
        response.raise_for_status()
        articles = response.json().get("articles", [])
        if not articles:
            return f"No news found for: {query}"
        lines = []
        for a in articles[:max_results]:
            lines.append(f"- {a['title']} ({a['source']['name']})")
            if a.get("description"):
                lines.append(f"  {a['description'][:120]}")
        return "\n".join(lines)
    except httpx.TimeoutException:
        return "Error: news API timed out."
    except httpx.HTTPStatusError as e:
        return f"Error: news API returned {e.response.status_code}."
    except Exception as e:
        return f"Error: {e}"

import httpx, os

SLACK_BOT_TOKEN = os.environ.get("SLACK_BOT_TOKEN", "")

def post_slack_message(channel: str, message: str) -> str:
    """
    Post a message to a Slack channel.
    channel: Slack channel ID (e.g. 'C1234567890') or name (e.g. '#general').
    message: The text message to post.
    """
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN environment variable not set."

    # Restrict to allowed channels for safety
    ALLOWED_CHANNELS = {"#alerts", "#agent-output", "C1234567890"}
    if channel not in ALLOWED_CHANNELS:
        return f"Error: channel '{channel}' is not in the allowed list. Use: {ALLOWED_CHANNELS}"

    try:
        response = httpx.post(
            "https://slack.com/api/chat.postMessage",
            headers={
                "Authorization": f"Bearer {SLACK_BOT_TOKEN}",
                "Content-Type": "application/json",
            },
            json={"channel": channel, "text": message},
            timeout=10.0,
        )
        response.raise_for_status()
        data = response.json()
        if data.get("ok"):
            return f"Message posted to {channel} at {data['message']['ts']}"
        else:
            return f"Slack error: {data.get('error', 'unknown error')}"
    except httpx.TimeoutException:
        return "Error: Slack API timed out."
    except Exception as e:
        return f"Error posting to Slack: {e}"

